12	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
13	type Customer = { yearsWithMHPCO: number };
14	type QuoteStep = { op: "quote"; items: Item[] };
15	type Scenario = { customer: Customer; steps: QuoteStep[] };
16	
17	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	
22	const groupByType = (items: Item[]): Item[][] => {
23	  const groups = new Map<string, Item[]>();
24	  for (const item of items) {
25	    const group = groups.get(item.type) ?? [];
26	    group.push(item);
27	    groups.set(item.type, group);
28	  }
29	  return [...groups.values()];
30	};
31	
32	const sumOfBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
34	
35	const basePremiumForGroup = (group: Item[]): number =>
36	  group.length === COMPONENT_BLOCK_SIZE
37	    ? COMPONENT_BLOCK_PREMIUM
38	    : sumOfBasePremiums(group);
39	
40	const totalBasePremium = (items: Item[]): number =>
41	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
42	
43	const CURSE_SURCHARGE_RATE = 0.5;
44	const HIGH_ENCHANTMENT_RATE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const FIRST_INSURANCE_RATE = 0.1;
47	const LOYALTY_DISCOUNT_RATE = -0.2;
48	const LOYALTY_YEARS_THRESHOLD = 2;
49	
50	const isCursed = (item: Item): boolean => item.cursed === true;
51	const isHighlyEnchanted = (item: Item): boolean =>
52	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
53	
54	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
55	
56	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
57	  modifiers.reduce((sum, { applies, rate }) => sum + (applies(subject) ? rate : 0), 0);
58	
59	const ITEM_SURCHARGES: Modifier<Item>[] = [
60	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
61	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
62	];
63	
64	const isFirstInsurance = (_customer: Customer): boolean => true;
65	const isLoyalCustomer = (customer: Customer): boolean =>
66	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
67	
68	const POLICY_MODIFIERS: Modifier<Customer>[] = [
69	  { applies: isFirstInsurance, rate: FIRST_INSURANCE_RATE },
70	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
71	];
72	
73	const totalPolicyModifiers = (baseTotal: number, customer: Customer): number =>
74	  baseTotal * sumApplicableRates(POLICY_MODIFIERS, customer);
75	
76	const itemSurchargesFor = (item: Item): number =>
77	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
78	
79	const totalItemSurcharges = (items: Item[]): number =>
80	  items.reduce((sum, item) => sum + itemSurchargesFor(item), 0);
81	
82	const premiumFor = (items: Item[], customer: Customer): number => {
83	  const baseTotal = totalBasePremium(items);
84	  return Math.ceil(
85	    baseTotal +
86	      totalItemSurcharges(items) +
87	      totalPolicyModifiers(baseTotal, customer) +
88	      PROCESSING_FEE,
89	  );
90	};
91	
92	const resultFor = (step: QuoteStep, customer: Customer) => ({
93	  premium: premiumFor(step.items, customer),
94	});
95	
96	export const runScenario = (input: unknown): unknown => {
97	  const scenario = input as Scenario;
98	  return { results: scenario.steps.map((step) => resultFor(step, scenario.customer)) };
99	};
